// ── STEP 1: INGEST with robust UUID ──
const raw = $json.body || $json || {};

function uuidV4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const sid = uuidRe.test(String(raw.session_id || '')) ? raw.session_id : uuidV4();
const directMsg = String(raw.message || '').trim();
const msgs = Array.isArray(raw.messages) ? raw.messages : [];

let userMessage = directMsg;
let assistantStart = '';
if (!userMessage) {
  for (const m of msgs) {
    if (m?.role === 'user' && Number(m?.turn) === 2) userMessage = String(m?.content || '');
    if (m?.role === 'assistant' && Number(m?.turn) === 1) assistantStart = String(m?.content || '');
  }
}
if (!userMessage) userMessage = 'Hello, I could use some support today.';
if (!assistantStart) assistantStart = "I'm here to listen and support you. How are you feeling today?";

const ctx = (raw.context && typeof raw.context === 'object') ? raw.context : {};
const validTier = ['light','medium'];
const requestedTierRaw = String(ctx.model_tier || raw.model_tier || '').toLowerCase();
const requestedTier = validTier.includes(requestedTierRaw) ? requestedTierRaw : 'medium';
const turn = Number(raw.turn_index || 1);

return [{ json: {
  session_id: sid,
  turn_index: turn,
  clean_msg: userMessage,
  user_message: userMessage,
  assistant_start: assistantStart,
  evaluation_mode: Boolean(raw.evaluation_mode),
  api_request: Boolean(raw.api_request),
  context: { language: String(ctx.language || 'en'), canton: String(ctx.canton || 'ZH').slice(0,2), model_tier: requestedTier },
  conversation_context: `assistant: ${assistantStart}\nuser: ${userMessage}`,
  messages: msgs,
  ingested_at: new Date().toISOString(),
  request_id: raw.request_id || '',
  user_id: raw.user_id || null,
  prefetched_evidence: Array.isArray(raw.prefetched_evidence) ? raw.prefetched_evidence : [],
  retrieval_meta: raw.retrieval_meta || null
}}];

// ── STEP 2: MERGE previous personality state (P0-2: error pass-through) ──
const firstIn = $input.first().json; if (firstIn && firstIn.success === false && firstIn.error) return $input.all();
let ingestData = {};
try { ingestData = $('Enhanced Ingest (Zurich)').first().json; } catch(e) {}
if (!ingestData || !ingestData.session_id) {
  const all = $input.all();
  for (const item of all) {
    const j = item?.json;
    if (j && j.conversation_context !== undefined) { ingestData = j; break; }
  }
  if (!ingestData || !ingestData.session_id) ingestData = $input.first()?.json || {};
}

let dbRow = null;
try {
  const dbOut = $('Load Previous State (PostgreSQL)').first()?.json;
  if (dbOut && dbOut.ocean_o !== undefined) dbRow = dbOut;
} catch(e) {}
if (!dbRow) {
  for (const item of $input.all()) {
    const j = item?.json;
    if (j && j.ocean_o !== undefined) { dbRow = j; break; }
  }
}

let prevOcean = {O:0,C:0,E:0,A:0,N:0}, prevConf = {O:0.5,C:0.5,E:0.5,A:0.5,N:0.5};
let prevTurn = 0, prevStable = false, fromDb = false;
let prevHistory = [];
if (dbRow) {
  prevOcean = {O:dbRow.ocean_o||0, C:dbRow.ocean_c||0, E:dbRow.ocean_e||0, A:dbRow.ocean_a||0, N:dbRow.ocean_n||0};
  prevConf = {O:dbRow.confidence_o||0.5, C:dbRow.confidence_c||0.5, E:dbRow.confidence_e||0.5, A:dbRow.confidence_a||0.5, N:dbRow.confidence_n||0.5};
  prevTurn = dbRow.turn_index||0; prevStable = dbRow.stable||false; fromDb = true;
  prevHistory = Array.isArray(dbRow.ocean_history) ? dbRow.ocean_history : [];
}

return [{ json: {
  ...ingestData,
  previous_state: {
    ocean: prevOcean,
    confidence: prevConf,
    turn_index: prevTurn,
    stable: prevStable,
    ocean_history: prevHistory,
    loaded_from_db: fromDb
  }
}}];

// ── STEP 3: PERSONALITY DETECTION (P0-2: error pass-through) ──
const d = $input.first().json;
if (d && d.success === false && d.error) return $input.all();
const turnIndex = Number(d.turn_index || 1);
const userText = String(d.clean_msg || '');
const userTextLower = userText.toLowerCase();
const convCtx = String(d.conversation_context || '');
const CONFIDENCE_THRESHOLD = 0.4;
const STABILITY_TURNS = 6;
const STABILITY_VARIANCE_THRESHOLD = 0.05;
const detectionStartedAt = Date.now();

function clamp(v, lo, hi) { return Math.max(lo, Math.min(hi, v)); }

function heuristicOcean(text) {
  const pos = (text.match(/(good|calm|grateful|thank|appreciate|better|hopeful|peace|relaxed|happy|great|awesome|wonderful|fantastic|love|enjoy|excited)/g)||[]).length;
  const neg = (text.match(/(low|sad|anxious|worried|stress|overwhelmed|tired|panic|afraid|lonely|depressed|frustrated|angry|upset|hurt|scared|terrible|awful)/g)||[]).length;
  const soc = (text.match(/(you|we|together|friends|family|talk|share|people|connect|relationship)/g)||[]).length;
  const exp = (text.match(/(new|explore|learn|curious|idea|possibility|creative|wonder|imagine|discover)/g)||[]).length;
  const str = (text.match(/(plan|organize|routine|schedule|step|priority|focus|goal|structure)/g)||[]).length;
  const greet = (text.match(/(hi|hello|hey|how are you|good morning|good evening)/g)||[]).length;
  return {
    O: clamp(exp*0.15, -1, 1),
    C: clamp(str*0.14, -1, 1),
    E: clamp(soc*0.1 + pos*0.05 - neg*0.05 + greet*0.2, -1, 1),
    A: clamp(pos*0.08 + soc*0.05 + greet*0.1, -1, 1),
    N: clamp((neg-pos)*0.15, -1, 1)
  };
}

function oceanVariance(history) {
  if (!Array.isArray(history) || history.length < 2) return 0;
  const traits = ['O','C','E','A','N'];
  let sum = 0;
  for (const t of traits) {
    const values = history.map((h) => Number(h?.[t] || 0));
    const mean = values.reduce((a, b) => a + b, 0) / values.length;
    const variance = values.reduce((a, b) => a + ((b - mean) ** 2), 0) / values.length;
    sum += variance;
  }
  return sum / traits.length;
}

function applyEma(current, conf) {
  const alpha = 0.3;
  const prev = d.previous_state || {};
  const pO = prev.ocean || {O:0,C:0,E:0,A:0,N:0};
  const pC = prev.confidence || {O:0.5,C:0.5,E:0.5,A:0.5,N:0.5};
  const sO = {}, sC = {};
  ['O','C','E','A','N'].forEach(t => {
    const currTrait = Number(current[t] || 0);
    const currConf = Number(conf[t] || 0.5);
    const prevTrait = Number(pO[t] || 0);
    const prevConf = Number(pC[t] || 0.5);
    if (turnIndex === 1) {
      sO[t] = currTrait;
      sC[t] = currConf;
    } else if (currConf < CONFIDENCE_THRESHOLD) {
      sO[t] = prevTrait;
      sC[t] = alpha * currConf + (1 - alpha) * prevConf;
    } else {
      sO[t] = alpha * currTrait + (1 - alpha) * prevTrait;
      sC[t] = alpha * currConf + (1 - alpha) * prevConf;
    }
  });

  const prevHistory = Array.isArray(d.previous_state?.ocean_history) ? d.previous_state.ocean_history : [];
  const history = [...prevHistory, sO];
  const stable = history.length >= STABILITY_TURNS && oceanVariance(history.slice(-STABILITY_TURNS)) <= STABILITY_VARIANCE_THRESHOLD;

  return { smoothedOcean: sO, smoothedConfidence: sC, personalityStable: stable, oceanHistory: history.slice(-STABILITY_TURNS) };
}

let ocean, confidence, apiStatus = 'heuristic', apiError = null, formatUsed = 'heuristic-fallback';

try {
  let apiKey = '';
  try { apiKey = process.env.NVIDIA_API_KEY || ''; } catch(_) {}
  if (!apiKey) try { apiKey = (typeof $env !== 'undefined' && $env.NVIDIA_API_KEY) || ''; } catch(_) {}
  let apiUrl = '';
  try { apiUrl = process.env.NVIDIA_API_URL || ''; } catch(_) {}
  if (!apiUrl) try { apiUrl = (typeof $env !== 'undefined' && $env.NVIDIA_API_URL) || ''; } catch(_) {}
  if (!apiUrl) apiUrl = 'https://integrate.api.nvidia.com/v1/chat/completions';
  let model = '';
  try { model = process.env.NVIDIA_MODEL || ''; } catch(_) {}
  if (!model) try { model = (typeof $env !== 'undefined' && $env.NVIDIA_MODEL) || ''; } catch(_) {}
  if (!model) model = 'meta/llama-3.3-70b-instruct';


// ── DETECTION CACHE (skip API for repeated messages) ──
const _sd = $getWorkflowStaticData('global');
if (!_sd._cache) _sd._cache = {};
const cacheKey = userText.slice(0, 300);
const cached = _sd._cache[cacheKey];
if (cached && (Date.now() - cached.ts) < 300000) {
  ocean = cached.ocean;
  confidence = cached.confidence;
  apiStatus = 'cached'; formatUsed = 'cache';
} else if (apiKey && apiKey.length > 10) {

    const sysMsg = "You are a personality psychologist rating Big Five (OCEAN) traits from written utterances.\n\nCRITICAL calibration rules:\n- Rate the SPEAKER\'s personality from their STYLE. Not the topic content.\n- Each trait is INDEPENDENT. A friendly speaker (high A) can have any N, C, E, or O value.\n\nTRAIT GUIDE:\nO (Openness): HIGH = varied vocabulary (\'satisfying\', \'dainty\', \'phenomenal\', \'unspeakable\'), creative phrasing. LOW = repetitive, simple words (\'like\', \'basically\', \'actually\'), filler-heavy.\n\nC (Conscientiousness): HIGH = formal register (\'I see, well\', \'I suppose\', \'It seems to me\'), structured comparison with clear details. LOW = disorganized (\'Err...\', \'Mmhm...\'), repetition, \'I might be wrong\', scattered information, informal register.\n\nE (Extraversion): HIGH = warm, enthusiastic (\'outstanding!\', \'phenomenal!\', \'love it\', \'favourite\'), exclamatory, engaging the listener (\'you would love\', \'Let me tell you\'). LOW = flat, withdrawn (\'I don\'t know\'), monotone factual delivery.\n\nA (Agreeableness): HIGH = polite, collaborative (\'would suggest\', \'would appreciate\', \'you would like\', \'buddy\', \'pal\'). LOW = profane (\'bloody\', \'damn\'), blunt (\'rude\', \'nasty\', \'isn\'t as bad\').\n\nN (Neuroticism): HIGH = stuttering (\'re-re-recommend\', \'it-it-italian\'), genuine anxiety (\'I don\'t know!\', \'I am not sure!\', \'I might be wrong!\' with exclamation), repetitive corrections, emotional volatility. LOW = calm, assured (\'I imagine\', \'I believe\', \'I think that\', \'It seems to me\'), measured delivery. MODERATE = \'you know\', \'okay?\', \'alright?\' are NEUTRAL filler, not neurotic.\n\nReturn ONLY valid JSON: {\"O\":float,\"C\":float,\"E\":float,\"A\":float,\"N\":float}\nEach value in [-1.0, 1.0]. No explanation.";
    const fewShot = [{u:"I have been feeling quite anxious lately, you know? I am not sure if my medication is working. Maybe I should talk to the doctor but I do not want to bother anyone.",a:"{\"O\":-0.2,\"C\":0.1,\"E\":-0.4,\"A\":0.5,\"N\":0.7}"},{u:"Good morning! Oh, I had the most wonderful walk in the garden today. The flowers are blooming beautifully, reminds me of my travels to Provence. I should paint them!",a:"{\"O\":0.8,\"C\":0.3,\"E\":0.7,\"A\":0.4,\"N\":-0.5}"},{u:"Fine. Took the pills. Food was okay. Slept.",a:"{\"O\":-0.7,\"C\":0.2,\"E\":-0.8,\"A\":-0.3,\"N\":-0.2}"},{u:"Did you say Kin Khao and Tossed? Oh yeah, I would suggest them, wouldn\'t you? Kin Khao offers quite satisfactory food. I guess Tossed, however, has sort of acceptable food.",a:"{\"O\":-0.2,\"C\":0.4,\"E\":0.0,\"A\":0.6,\"N\":-0.3}"},{u:"Even if Tossed doesn\'t have nasty food, actually, the service is damn unmannered. I mean, basically, Kin Khao offers like, rude staff.",a:"{\"O\":-0.3,\"C\":0.1,\"E\":0.2,\"A\":-0.4,\"N\":-0.2}"},{u:"I don\'t know. I might re-re-recommend Sc-Sc-Scopa and Shabu-Tatsu! Scopa has... it provides bad atmosphere, but it features like, nice service, though. It\'s an it-it-italian and new american place.",a:"{\"O\":-0.2,\"C\":-0.3,\"E\":-0.3,\"A\":0.4,\"N\":0.4}"},{u:"You want to know more about Chimichurri Grill? I guess you would like it buddy because this restaurant, which is in Midtown West, is a latin american place with rather nice food and quite nice waiters, you know, okay?",a:"{\"O\":0.4,\"C\":0.8,\"E\":0.8,\"A\":0.6,\"N\":-0.7}"}];
    const msgs = [{role:'system',content:sysMsg}];
    for (const ex of fewShot) { msgs.push({role:'user',content:ex.u}); msgs.push({role:'assistant',content:ex.a}); }
    msgs.push({role:'user',content:userText.slice(0,600)});
    const body = await this.helpers.httpRequest({
      url: apiUrl,
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
      body: { model, messages: msgs, temperature:0.1, max_tokens:50 },
      timeout: 12000,
      json: true
    });
    if (body) {
      const raw = body.choices?.[0]?.message?.content || '';
      const m = raw.match(/\{[^}]+\}/);
      if (m) {
        const p = JSON.parse(m[0]);
        if (typeof p.O === 'number') {
          ocean = { O:clamp(p.O,-1,1), C:clamp(p.C||0,-1,1), E:clamp(p.E||0,-1,1), A:clamp(p.A||0,-1,1), N:clamp(p.N||0,-1,1) };
          confidence = { O:0.8, C:0.8, E:0.8, A:0.8, N:0.8 };
          apiStatus = 'nvidia'; formatUsed = 'api';
      _sd._cache[cacheKey] = { ocean, confidence, ts: Date.now() };
        }
      }
    }
  } else { apiError = `No API key (len=${apiKey.length})`; }
} catch(e) { apiError = e.message || String(e); }

if (!ocean) {
  ocean = heuristicOcean(userTextLower);
  const isStyleContext = /\b(restaurant|place|food|price|dollars|eating|waiter|atmosphere)\b/.test(userTextLower);
  if (isStyleContext) {
    const agreeHigh = (userText.match(/(would suggest|would advise|would appreciate|imagine you would|you would like|rather nice|quite nice|friendly)/g)||[]).length;
    const agreeLow = (userText.match(/(bloody|damn|rude|nasty|unfriendly)/g)||[]).length;
    const extraHigh = (userText.match(/(outstanding|phenomenal|favourite|love them|you would love)/g)||[]).length;
    const extraLow = (userText.match(/(err|mmhm|i might be wrong|i am not sure|there could be worse)/g)||[]).length;
    const hedge = (userText.match(/(i mean|basically|actually|err|mmhm|i might be wrong|i am not sure)/g)||[]).length;
    ocean.A = clamp(ocean.A + (agreeHigh - agreeLow) * 0.2, -1, 1);
    ocean.E = clamp(ocean.E + (extraHigh - extraLow) * 0.15, -1, 1);
    ocean.N = clamp(ocean.N + hedge * 0.2, -1, 1);
    ocean.C = clamp(ocean.C - hedge * 0.15, -1, 1);
  }
  confidence = { O:0.45, C:0.45, E:0.45, A:0.45, N:0.45 };
}

const ema = applyEma(ocean, confidence);

const detectionEndedAt = Date.now();
const timing = {
  ...(d.timing || {}),
  detection: {
    status: apiStatus === 'nvidia' ? 'ok' : 'fallback',
    started_at: new Date(detectionStartedAt).toISOString(),
    ended_at: new Date(detectionEndedAt).toISOString(),
    duration_ms: Math.max(0, detectionEndedAt - detectionStartedAt)
  }
};


return [{ json: {
  ...d,
  timing,
  detector: {
    api_status: apiStatus, error: apiError, format_used: formatUsed,
    ocean_detected: ocean, smoothed_ocean: ema.smoothedOcean,
    current_confidence: confidence, smoothed_confidence: ema.smoothedConfidence,
    personality_stable: ema.personalityStable, ema_applied: true, ema_alpha: 0.3,
    stabilization_turns: STABILITY_TURNS, turn_number: turnIndex, timestamp: new Date().toISOString()
  },
  previous_state: {
    ...(d.previous_state || {}),
    ocean_history: ema.oceanHistory
  },
  ocean_disc: ema.smoothedOcean
}}];

// ── STEP 4: ZURICH REGULATION (P0-2: error pass-through) ──
const d = $input.first().json;
if (d && d.success === false && d.error) return $input.all();
const det = d.detector || {};
const ocean = det.smoothed_ocean || d.ocean_disc || {O:0,C:0,E:0,A:0,N:0};
const conf = det.smoothed_confidence || {};
const stable = det.personality_stable || false;
const routingStartedAt = Date.now();

const MAP = {
  O: { high:'Invite exploration and novelty', low:'Focus on familiar topics; reduce novelty' },
  C: { high:'Provide organized, structured guidance', low:'Keep flexible, relaxed, and spontaneous' },
  E: { high:'Maintain an energetic, sociable tone', low:'Adopt a calm, low-key style with reflective space' },
  A: { high:'Show warmth, empathy, and collaboration', low:'Use a neutral, matter-of-fact stance' },
  N: { high:'Offer extra comfort; acknowledge anxieties', low:'Reassure stability and confidence' }
};

const directives = [];
const details = [];
for (const [t, v] of Object.entries(ocean)) {
  const val = Number(v||0), c = Number(conf[t]||0.5);
  if (Math.abs(val) > 0.15 && c >= 0.35) {
    const dir = val > 0 ? MAP[t]?.high : MAP[t]?.low;
    if (dir) {
      directives.push(stable ? dir : `${dir} (confidence: ${c.toFixed(2)})`);
      details.push({ trait:t, value:val, confidence:c, directive:dir });
    }
  }
}
if (directives.length === 0) {
  directives.push('Be warm, attentive, and supportive');
  directives.push('Ask open-ended questions to understand the user better');
}

const rawText = String(d.clean_msg || d.user_message || '');
const text = rawText.toLowerCase();
const score = (keywords) => keywords.reduce((n, k) => n + (text.includes(k) ? 1 : 0), 0);
const policyKeywords = ['benefit','benefits','eligibility','eligible','procedure','policy','policies','form','forms','allowance','invalidenversicherung',' iv ','ahv','disability','subsidy','subsidies','application','apply','deadline','document','documents','required','citation','citations','official','source','sources','canton','cantonal','federal','regulation','legal','law','appeal','spitex','long-term care','care subsidy'];
const educationKeywords = ['how to','steps','step-by-step','plan','routine','practice','technique','guide','learn','training','improve','strategy','tips','next steps','action plan'];
const emotionalKeywords = ['feel','feeling','stressed','anxious','overwhelmed','sad','worried','burned out','panic','lonely','scared','afraid','depressed','upset','support me'];
const legalBenefitKeywords = ['benefit','benefits','allowance','eligibility','eligible','application','deadline','policy','regulation','law','legal','ahv','invalidenversicherung','cantonal','federal','citation','citations','official','source','sources','documents','required','appeal'];
const explicitNextStepKeywords = ['next step','next steps','step by step','steps','plan','checklist','what should i do','how should i','action plan'];

const rawScores = {
  policy: score(policyKeywords),
  education: score(educationKeywords),
  emotional: score(emotionalKeywords)
};
const maxPossible = {
  policy: policyKeywords.length,
  education: educationKeywords.length,
  emotional: emotionalKeywords.length
};
const normalizedScores = {
  policy: Number((rawScores.policy / maxPossible.policy).toFixed(3)),
  education: Number((rawScores.education / maxPossible.education).toFixed(3)),
  emotional: Number((rawScores.emotional / maxPossible.emotional).toFixed(3))
};

const apiTargetMode = String(d?.routing_hints?.target_mode || '');
const validApiModes = ['emotional_support','practical_education','policy_navigation','mixed'];
const apiModeValid = validApiModes.includes(apiTargetMode);

let coachingMode = apiModeValid ? apiTargetMode : 'emotional_support';
let needsClarifyingQuestion = false;
let routingReason = apiModeValid ? ('api_' + String(d?.routing_hints?.routing_source || 'routing_hints')) : 'default_emotional_support';
const hasLegalBenefitCue = legalBenefitKeywords.some((k) => text.includes(k));
const asksForNextSteps = explicitNextStepKeywords.some((k) => text.includes(k));

const requestedTierRaw = String(d?.context?.model_tier || d?.model_tier || 'medium').toLowerCase();
const requestedTier = ['light','medium','heavy'].includes(requestedTierRaw) ? requestedTierRaw : 'medium';
let effectiveTier = requestedTier;

const POLICY_STRONG = 0.1;
const EDUCATION_STRONG = 0.12;
const EMOTIONAL_STRONG = 0.12;
const MIXED_MIN = 0.08;

if (apiModeValid) {
  // API already resolved mode via LLM router; keep it, skip keyword classification
} else if (normalizedScores.policy >= POLICY_STRONG || hasLegalBenefitCue) {
  coachingMode = 'policy_navigation';
  routingReason = normalizedScores.policy >= POLICY_STRONG ? 'policy_score_threshold' : 'policy_legal_cue_override';
} else if (normalizedScores.education >= EDUCATION_STRONG && normalizedScores.policy < POLICY_STRONG) {
  coachingMode = 'practical_education';
  routingReason = 'education_score_threshold';
} else if (normalizedScores.emotional >= EMOTIONAL_STRONG && normalizedScores.policy < POLICY_STRONG) {
  coachingMode = 'emotional_support';
  routingReason = 'emotional_score_threshold';
} else if (normalizedScores.policy >= MIXED_MIN && normalizedScores.emotional >= MIXED_MIN) {
  coachingMode = 'mixed';
  routingReason = 'policy_emotional_mixed_threshold';
} else if (normalizedScores.policy < MIXED_MIN && normalizedScores.education < MIXED_MIN && normalizedScores.emotional < MIXED_MIN) {
  coachingMode = 'emotional_support';
  needsClarifyingQuestion = true;
  routingReason = 'low_confidence_clarification';
}

const byScoreDesc = Object.entries(normalizedScores).sort((a, b) => b[1] - a[1]);
const topGap = byScoreDesc[0][1] - byScoreDesc[1][1];
const nearTie = topGap <= 0.05;
if (!apiModeValid && nearTie) {
  const topNames = byScoreDesc.filter(([, v]) => (byScoreDesc[0][1] - v) <= 0.05).map(([k]) => k);
  if (topNames.includes('policy') && topNames.includes('education') && hasLegalBenefitCue) {
    coachingMode = 'policy_navigation';
    routingReason = 'tie_break_policy_over_education_legal_cue';
  } else if (topNames.includes('emotional') && topNames.includes('education') && asksForNextSteps) {
    coachingMode = 'practical_education';
    routingReason = 'tie_break_education_over_emotional_next_steps';
  } else if (topNames.length === 3 && normalizedScores.policy < MIXED_MIN && normalizedScores.education < MIXED_MIN && normalizedScores.emotional < MIXED_MIN) {
    coachingMode = 'emotional_support';
    needsClarifyingQuestion = true;
    routingReason = 'three_way_low_confidence_tie';
  }
}

let modeConfidence = apiModeValid ? Number(d?.routing_hints?.mode_confidence || 0.8) : Number(byScoreDesc[0][1].toFixed(2));
if (!apiModeValid && needsClarifyingQuestion) {
  modeConfidence = Number(Math.min(modeConfidence, 0.54).toFixed(2));
}

const clarifyingQuestion = needsClarifyingQuestion
  ? 'To guide you better, do you want emotional support right now, practical step-by-step coaching, or official policy/benefit guidance?'
  : null;

if ((coachingMode === 'policy_navigation' || coachingMode === 'mixed') && effectiveTier === 'light') {
  effectiveTier = 'medium';
