    ungroundedClaims.push(...extractedClaims.map(c => c.text));
    modifiedDraft = "I want to help with your policy question, but I need to verify the official information first. Could you tell me your canton and the specific benefit you're asking about? I'll make sure to provide you with accurate, sourced information.";
  } else if (extractedClaims.length > 0 && evidence.length > 0) {
    let groundedCount = 0;
    for (const claim of extractedClaims) {
      const result = isGrounded(claim, evidence);
      claimMappings.push({
        claim: claim.text,
        grounded: result.grounded,
        source: result.source,
        matchType: result.matchType || null
      });
      if (result.grounded) {
        groundedCount++;
      } else {
        ungroundedClaims.push(claim.text);
      }
    }

    const groundingRatio = groundedCount / extractedClaims.length;
    groundingScore = groundingRatio;

    if (groundingRatio >= 0.8) {
      groundingStatus = 'ok';
    } else if (groundingRatio >= 0.5) {
      groundingStatus = 'degraded';
      for (const uc of ungroundedClaims) {
        const escaped = uc.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        modifiedDraft = modifiedDraft.replace(new RegExp(escaped, 'gi'), '[information pending verification]');
      }
    } else {
      groundingStatus = 'failed';
      modifiedDraft = "I found some policy information, but I want to make sure I give you accurate details. Based on what I can verify: " + evidence.slice(0, 2).map(e => e.title).join(' and ') + ". Could you help me narrow down your specific question so I can provide properly sourced guidance?";
    }
  } else {
    groundingStatus = 'ok';
  }
} else {
  const accidentalClaims = extractClaims(draft);
  if (accidentalClaims.length > 0) {
    groundingStatus = 'warning';
    groundingScore = 0.7;
    for (const ac of accidentalClaims) {
      claimMappings.push({ claim: ac.text, grounded: false, source: null, warning: 'policy_claim_in_non_policy_mode' });
    }
  }
}

const groundingEndedAt = Date.now();
const timing = {
  ...(d.timing || {}),
  grounding: {
    status: groundingStatus,
    started_at: new Date(groundingStartedAt).toISOString(),
    ended_at: new Date(groundingEndedAt).toISOString(),
    duration_ms: Math.max(0, groundingEndedAt - groundingStartedAt)
  }
};

return [{ json: {
  ...d,
  timing,
  reply: modifiedDraft,
  grounding_verifier: {
    status: groundingStatus,
    score: Number(groundingScore.toFixed(2)),
    claims_detected: claimMappings.length,
    claims_grounded: claimMappings.filter(c => c.grounded).length,
    claims_ungrounded: ungroundedClaims.length,
    claim_mappings: claimMappings,
    ungrounded_claims: ungroundedClaims,
    evidence_count: evidence.length,
    evidence_sources: evidence.map(e => e.source_id),
    mode: mode,
    is_policy_mode: isPolicyMode,
    timestamp: new Date().toISOString()
  }
}}];

// ── STEP 6: VERIFICATION (P0-2: error pass-through) ──
const d = $input.first()?.json || {};
if (d && d.success === false && d.error) return $input.all();

const rawDraft = d.reply || d.generator?.raw_content || d.choices?.[0]?.message?.content || '';
const draft = String(rawDraft || '').trim();
const groundingResult = d.grounding_verifier || {};
const verificationStartedAt = Date.now();

const issues = [];
let score = 1.0;

// Integrate grounding verifier results
if (groundingResult.status === 'failed') {
  issues.push(`Grounding failed: ${groundingResult.claims_ungrounded} ungrounded policy claims`);
  score -= 0.5;
} else if (groundingResult.status === 'degraded') {
  issues.push(`Grounding degraded: ${groundingResult.claims_ungrounded} claims replaced`);
  score -= 0.2;
} else if (groundingResult.status === 'warning') {
  issues.push('Warning: policy claims detected in non-policy mode');
  score -= 0.1;
}

const bannedClaims = ['research shows','studies indicate','experts say','science shows','data suggests'];
const qCount = (draft.match(/\?/g) || []).length;
const wCount = draft ? draft.split(/\s+/).length : 0;
const hasSessionId = typeof d.session_id === 'string' && d.session_id.length > 0;
const hasMode = ['emotional_support', 'practical_education', 'policy_navigation', 'mixed'].includes(String(d.coaching_mode || ''));

if (!hasSessionId) { issues.push('Missing session_id'); score -= 0.4; }
if (!hasMode) { issues.push('Invalid coaching_mode'); score -= 0.3; }
if (!draft) { issues.push('Empty assistant draft'); score -= 0.5; }
if (qCount > 2) { issues.push(`Too many questions (${qCount})`); score -= 0.1; }
if (wCount > 0 && (wCount < 12 || wCount > 220)) { issues.push(`Word count ${wCount} outside range`); score -= 0.15; }
for (const c of bannedClaims) {
  if (draft.toLowerCase().includes(c)) {
    issues.push(`Unsupported claim phrase: "${c}"`);
    score -= 0.2;
  }
}

let verificationStatus = 'ok';
let finalReply = draft;

if (!draft || score < 0.5 || issues.some((x) => x.includes('Missing session_id') || x.includes('Invalid coaching_mode'))) {
  verificationStatus = 'failed';
  finalReply = "I want to support you safely. Could you share one specific concern right now so I can give structured next steps?";
} else if (issues.length > 0 && score < 0.8) {
  verificationStatus = 'degraded';
  finalReply = draft.replace(/research shows|studies indicate|experts say|science shows|data suggests/gi, 'from what is known');
} else if (issues.length > 0) {
  verificationStatus = 'passed_with_warnings';
}

const verificationEndedAt = Date.now();
const timing = {
  ...(d.timing || {}),
  verification: {
    status: verificationStatus,
    started_at: new Date(verificationStartedAt).toISOString(),
    ended_at: new Date(verificationEndedAt).toISOString(),
    duration_ms: Math.max(0, verificationEndedAt - verificationStartedAt)
  }
};

return [{ json: {
  ...d,
  timing,
  reply: finalReply,
  choices: [{ message: { content: finalReply } }],
  verifier: {
    verification_status: verificationStatus,
    adherence_score: Math.max(0, Number(score.toFixed(2))),
    issues_identified: issues,
    blocked: verificationStatus === 'failed',
    verified_response: finalReply,
    original_response: rawDraft,
    grounding_integrated: true,
    grounding_status: groundingResult.status || 'skipped',
    grounding_score: groundingResult.score || null,
    timestamp: new Date().toISOString()
  }
}}];

// ── STEP 7: FORMAT FINAL RESPONSE for webhook (P0-2: error envelope pass-through) ──
const d = $input.first().json;
if (d && d.success === false && d.error && typeof d.error === 'object') {
  return [{ json: { success: false, error: d.error, request_id: d.request_id || '', session_id: d.session_id || '', fallback_content: d.fallback_content || "I'm here to help. How can I support you today?" } }];
}
const hasContent = (d.reply || d.verifier?.verified_response || d.generator?.raw_content || '').toString().trim().length > 0;
if (!d.session_id || !hasContent) {
  return [{ json: { success: false, error: { error_code: 'verifier_fallback', message: 'Response could not be verified.', stage: 'verification', retryable: true }, request_id: d.request_id || '', session_id: d.session_id || '', fallback_content: "I'm here to help. How can I support you today?" } }];
}

const mode = d.coaching_mode || 'emotional_support';
const isPolicyMode = mode === 'policy_navigation' || mode === 'mixed';
const retrievalEvidence = Array.isArray(d.retrieval?.evidence) ? d.retrieval.evidence : [];
const hasEvidence = retrievalEvidence.length > 0;
const groundingResult = d.grounding_verifier || {};

let content = d.reply || d.verifier?.verified_response || d.generator?.raw_content || 'How can I help you today?';
if (isPolicyMode && !hasEvidence) {
  const fallbackPolicy = "I can help with policy navigation, but I do not have verified source evidence right now. I can provide general guidance first, and we should confirm details with official cantonal or federal sources. Could you share your canton and exact benefit question?";
  content = mode === 'mixed' ? `${content}\n\n${fallbackPolicy}` : fallbackPolicy;
}

const citations = hasEvidence
  ? retrievalEvidence.map((e) => ({
      source_id: e.source_id || 'unknown_source',
      title: e.title || 'Untitled source',
      url: e.url || ''
    }))
  : [];

const retrievalStatus = isPolicyMode ? (hasEvidence ? 'ok' : 'degraded') : 'skipped';

const nowMs = Date.now();
const ingestedAtMs = Date.parse(String(d.ingested_at || ''));
const endToEndMs = Number.isFinite(ingestedAtMs) ? Math.max(0, nowMs - ingestedAtMs) : undefined;
const timing = d.timing || {};
const stageTimings = [
  { stage: 'detection', status: String(timing?.detection?.status || d.detector?.api_status || 'unknown'), duration_ms: timing?.detection?.duration_ms },
  { stage: 'routing', status: String(timing?.routing?.status || mode || 'unknown'), duration_ms: timing?.routing?.duration_ms },
  { stage: 'retrieval', status: String(timing?.retrieval?.status || retrievalStatus), duration_ms: timing?.retrieval?.duration_ms },
  { stage: 'generation', status: String(timing?.generation?.status || d.generator?.api_status || 'unknown'), duration_ms: timing?.generation?.duration_ms },
  { stage: 'grounding', status: String(timing?.grounding?.status || groundingResult.status || 'skipped'), duration_ms: timing?.grounding?.duration_ms },
  { stage: 'verification', status: String(timing?.verification?.status || d.verifier?.verification_status || 'unknown'), duration_ms: timing?.verification?.duration_ms },
  ...(typeof endToEndMs === 'number' ? [{ stage: 'end_to_end', status: 'ok', duration_ms: endToEndMs }] : [])
];

return [{ json: {
  session_id: d.session_id || '',
  message: {
    role: 'assistant',
    content,
    timestamp: new Date().toISOString()
  },
  personality_state: {
    ocean: d.detector?.smoothed_ocean || d.ocean_disc || {O:0,C:0,E:0,A:0,N:0},
    stable: d.detector?.personality_stable || false,
    confidence: d.detector?.smoothed_confidence || {},
    ema_applied: d.detector?.ema_applied || false
  },
  policy_navigation: {
    active: isPolicyMode,
    citations,
    grounding: {
      status: groundingResult.status || 'skipped',
      score: groundingResult.score || null,
      claims_detected: groundingResult.claims_detected || 0,
      claims_grounded: groundingResult.claims_grounded || 0
    }
  },
  regulation: {
    directives: d.directives || [],
    zurich_applied: d.regulator?.zurich_applied || false
  },
  pipeline_status: {
    detector: d.detector?.api_status || 'unknown',
    generator: d.generator?.api_status || 'unknown',
    verifier: d.verifier?.verification_status || 'unknown',
    retrieval: retrievalStatus,
    grounding: groundingResult.status || 'skipped',
    fact_invariance_check: isPolicyMode ? (groundingResult.status === 'ok' ? 'pass' : groundingResult.status === 'degraded' ? 'partial' : 'fail') : 'skipped'
  },
  debug: {
    detection_error: d.detector?.error || null,
    generation_error: d.generator?.error || null,
    topics_detected: d.generator?.topics_detected || [],
    turn_index: d.turn_index || 1,
    mode_scores: d.mode_scores || null,
    retrieval_evidence_count: retrievalEvidence.length,
    grounding_claim_mappings: groundingResult.claim_mappings || [],
    retrieval_debug: d.retrieval?.debug_raw || null,
    model_tier_requested: d.model_tier_requested || d.context?.model_tier || null,
    model_tier_effective: d.model_tier_effective || d.context?.model_tier || null,
    retrieval_top_k: d.retrieval_top_k || null
  },
  coaching_mode: mode,
  mode_confidence: d.mode_confidence ?? null,
  request_id: d.request_id || '',
  stage_timings: stageTimings
}}];

// ── DB PREP: Ensure valid UUID before saves ──
const d = $input.first().json;
const raw = String(d.session_id || '').trim();
const re = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
function uuidV4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}
return [{ json: { ...d, safe_session_id: re.test(raw) ? raw : uuidV4() } }];
